def average_color(colors):
    if not colors:
        return (0, 0, 0)
    r_sum, g_sum, b_sum = 0, 0, 0
    for r, g, b in colors:
        r_sum += r
        g_sum += g
        b_sum += b
    count = len(colors)
    return (round(r_sum / count), round(g_sum / count), round(b_sum / count))
